INSERT INTO `course_lessons` VALUES (4,2,3,'Hand hygiene & infection control','<p>Hand hygiene is the single most effective way to prevent the spread of infection. Follow the WHO 5 moments for hand hygiene.</p>',1,'2026-07-08 11:17:24','2026-07-08 11:17:24'),(5,2,3,'Recording vital signs','<p>Vital signs include temperature, pulse, respiration, blood pressure and oxygen saturation. Accurate measurement and documentation are essential.</p>',2,'2026-07-08 11:17:24','2026-07-08 11:17:24'),(6,3,4,'Routes of administration','<p>Oral, intravenous, intramuscular, subcutaneous and topical routes — each has advantages and precautions.</p>',1,'2026-07-08 11:17:24','2026-07-08 11:17:24');
