INSERT INTO `faq` VALUES (1,'What is Ekattor 8?','Ekattor 8 is a collection of programs designed to assist schools in administering their executive responsibilities on a day-to-day basis. Ekattor 8 is an updated version of Ekattor ERP (Enterprise Resource Planning). Also, Ekattor 8 is designed for SAAS (Software as a Service) projects.'),(2,'How can I get developed my customer features?','Custom features do not coming with product support. You can contact our support center and send us details about your requirement. If our schedule is open, we can give you a quotation and take your project according to the contract.'),(5,'Which license to choose for my client project?','If you use academy LMS for a commercial project of a client, you will be required extended license.'),(6,'How much time will I get developer support?','By default, you are entitled to developer support for 6 months from the date of your purchase. Later on anytime you can renew the support pack if you need developer support. If you don’t need any developer support, you don’t need to buy it.');
/*!40000 ALTER TABLE `faq` ENABLE KEYS */;
