INSERT INTO `questions` VALUES (2,1,3,1,1,'Organs','easy','mcq','Which is the largest organ of the human body?','[\"Skin\", \"Liver\", \"Heart\", \"Brain\"]','0',2,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(3,1,3,1,1,'Skeletal','medium','truefalse','The femur is located in the arm.','[\"True\", \"False\"]','false',1,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(4,1,3,1,1,'Cardio','easy','truefalse','The human heart has four chambers.','[\"True\", \"False\"]','true',1,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(5,1,3,1,1,'Cells','easy','short','What is the basic structural unit of life?',NULL,'cell',2,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(6,1,3,1,1,'Organisation','medium','essay','Describe the levels of structural organisation in the human body.',NULL,NULL,5,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(7,1,3,1,1,'Terminology','medium','mcq','The term \"anterior\" refers to which position?','[\"Front\", \"Back\", \"Above\", \"Below\"]','0',2,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(8,1,3,1,5,'Infection control','easy','mcq','What is the single most effective way to prevent the spread of infection?','[\"Hand hygiene\", \"Gloves\", \"Masks\", \"Gowns\"]','0',2,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(9,1,3,1,5,'Vitals','easy','truefalse','Blood pressure is one of the vital signs.','[\"True\", \"False\"]','true',1,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(10,1,3,1,5,'Vitals','medium','short','What is the lower bound of a normal adult resting heart rate (bpm)?',NULL,'60',1,'2026-07-08 14:18:58','2026-07-08 14:18:58'),(11,1,3,1,5,'Documentation','medium','essay','Explain why accurate documentation of vital signs is important in nursing.',NULL,NULL,4,'2026-07-08 14:18:58','2026-07-08 14:18:58');
